// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"context"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var auditLogger = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-audit")

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	lock     lock.Mutex
	logLevel logrus.Level
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the specified log level.
func NewPolicyAuditLogger(level logrus.Level) *PolicyAuditLogger {
	return &PolicyAuditLogger{
		logLevel: level,
	}
}

// LogDecision logs a policy decision with the provided parameters.
// identity: the identity that is the subject of the decision
// policy: the policy being evaluated
// verdict: the decision verdict (e.g., "ALLOW", "DENY")
// reason: the reason for the decision
func (pal *PolicyAuditLogger) LogDecision(identity, policy, verdict, reason string) {
	pal.lock.Lock()
	defer pal.lock.Unlock()

	if auditLogger.Logger.IsLevelEnabled(pal.logLevel) {
		auditLogger.WithFields(logrus.Fields{
			logfields.Identity: identity,
			"policy":           policy,
			"verdict":          verdict,
			"reason":           reason,
		}).Log(pal.logLevel, "Policy decision evaluated")
	}
}

// LogEvaluation logs a policy evaluation with detailed context information.
// ctx: context for the evaluation
// policyKey: the key identifying the policy being evaluated
// selectorCache: the SelectorCache used for identity matching
// result: the evaluation result
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result string) {
	pal.lock.Lock()
	defer pal.lock.Unlock()

	if auditLogger.Logger.IsLevelEnabled(pal.logLevel) {
		fields := logrus.Fields{
			logfields.PolicyKey: policyKey,
			"result":            result,
		}

		if selectorCache != nil {
			// Add selector cache statistics if available
			fields["selector_count"] = len(selectorCache.selectors)
		}

		auditLogger.WithFields(fields).Log(pal.logLevel, "Policy evaluation completed")
	}
}

