// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"context"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/labels"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.DebugLevel)
	require.NotNil(t, logger)
}

func TestLogDecision(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.DebugLevel)
	require.NotNil(t, logger)

	// Test logging a decision
	logger.LogDecision("identity-1", "policy-1", "ALLOW", "Default allow rule")
	logger.LogDecision("identity-2", "policy-2", "DENY", "Explicit deny rule")
}

func TestLogEvaluation(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.DebugLevel)
	require.NotNil(t, logger)

	ctx := context.Background()

	// Create a SelectorCache for testing
	ids := identity.IdentityMap{
		identity.ReservedIdentityHost: labels.NewLabelsFromModel([]string{"host"}),
	}
	selectorCache := NewSelectorCache(ids)

	// Test logging an evaluation
	logger.LogEvaluation(ctx, "policy-key-1", selectorCache, "ALLOW")
	logger.LogEvaluation(ctx, "policy-key-2", nil, "DENY")
}

func TestLogDecisionConcurrency(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)

	// Test concurrent logging
	done := make(chan bool)
	for i := 0; i < 10; i++ {
		go func(idx int) {
			logger.LogDecision("identity", "policy", "ALLOW", "test-reason")
			done <- true
		}(i)
	}

	for i := 0; i < 10; i++ {
		<-done
	}
}

func TestLogEvaluationConcurrency(t *testing.T) {
	logger := NewPolicyAuditLogger(logrus.InfoLevel)
	require.NotNil(t, logger)

	ctx := context.Background()
	ids := identity.IdentityMap{
		identity.ReservedIdentityHost: labels.NewLabelsFromModel([]string{"host"}),
	}
	selectorCache := NewSelectorCache(ids)

	// Test concurrent logging
	done := make(chan bool)
	for i := 0; i < 10; i++ {
		go func(idx int) {
			logger.LogEvaluation(ctx, "policy-key", selectorCache, "ALLOW")
			done <- true
		}(i)
	}

	for i := 0; i < 10; i++ {
		<-done
	}
}

func TestPolicyAuditLoggerLogLevels(t *testing.T) {
	testCases := []logrus.Level{
		logrus.DebugLevel,
		logrus.InfoLevel,
		logrus.WarnLevel,
		logrus.ErrorLevel,
	}

	for _, level := range testCases {
		t.Run(level.String(), func(t *testing.T) {
			logger := NewPolicyAuditLogger(level)
			require.NotNil(t, logger)
			require.Equal(t, level, logger.logLevel)

			// Verify logging at different levels works
			logger.LogDecision("identity", "policy", "ALLOW", "test")
			logger.LogEvaluation(context.Background(), "policy-key", nil, "ALLOW")
		})
	}
}

